  return (
    <div
      className="fixed inset-0 z-[60] flex items-end md:items-center justify-center animate-fade-in"
      onClick={onClose}
    >
      <div className="absolute inset-0 bg-brand-background/95 backdrop-blur-xl"></div>

      <div
        className="glass-pane w-full max-w-6xl max-h-[96vh] md:max-h-full md:rounded-[2.5rem] rounded-t-[3rem] flex flex-col md:flex-row overflow-hidden relative shadow-2xl border-white/10"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Close Button - Responsive Position */}
        <button
          onClick={onClose}
          className="absolute top-6 right-6 z-50 p-2.5 rounded-full bg-black/50 text-white backdrop-blur-md hover:bg-brand-accent hover:text-brand-background transition-all"
        >
          <XMarkIcon className="w-6 h-6" />
        </button>

        {/* Mobile View Structure (Matches Reference Image) */}
        <div className="md:hidden w-full overflow-y-auto no-scrollbar pb-10">
            {/* Header / Poster Area */}
            <div className="relative aspect-[4/5] w-full overflow-hidden">
                <img
                    src={movie.posterUrl}
                    alt={movie.title}
                    className="w-full h-full object-cover"
                    referrerPolicy="no-referrer"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-brand-background via-brand-background/20 to-transparent"></div>

                {/* Floating Action Buttons Area - Overlay on Image */}
                <div className="absolute top-20 right-4 flex flex-col gap-4">
                    <button onClick={openTrailer} disabled={!movie.trailerUrl} className="p-3.5 rounded-full bg-black/40 backdrop-blur-md text-white border border-white/10 active:scale-90 transition-transform disabled:opacity-30">
                        <PlayIcon className="w-6 h-6" />
                    </button>
                    <button onClick={onShareClick} className="p-3.5 rounded-full bg-black/40 backdrop-blur-md text-white border border-white/10 active:scale-90 transition-transform">
                        <ShareIcon className="w-6 h-6" />
                    </button>
                    <button onClick={onToggleWatchlist} className={`p-3.5 rounded-full backdrop-blur-md border border-white/10 active:scale-90 transition-transform ${isInWatchlist ? 'bg-brand-accent text-brand-background' : 'bg-black/40 text-white'}`}>
                        <BookmarkIcon className="w-6 h-6" />
                    </button>
                    <button onClick={onToggleWatched} className={`p-3.5 rounded-full backdrop-blur-md border border-white/10 active:scale-90 transition-transform ${isInWatchedList ? 'bg-emerald-500 text-white' : 'bg-black/40 text-white'}`}>
                        <EyeIcon className="w-6 h-6" />
                    </button>
                </div>

                <div className="absolute bottom-8 left-8 right-8">
                    <p className="text-xs font-black text-brand-accent tracking-widest uppercase mb-2">
                        {movie.type === 'Movie' ? 'Filme' : 'Série'}
                    </p>
                    <h2 className="text-4xl font-black text-white italic leading-tight tracking-tighter">
                        {movie.title} ({movie.year})
                    </h2>
                </div>
            </div>

            {/* Content Area */}
            <div className="px-8 space-y-8">
                {/* Rating Card (Matches Screenshot) */}
                {movie.ratings.imdb > 0 && (
                    <div className="pt-4 border-t border-white/5">
                        <div className="flex flex-col items-center">
                            <div className="flex items-baseline gap-1">
                                <span className="text-5xl font-black text-white">{movie.ratings.imdb.toFixed(1)}</span>
                                <span className="text-xl font-bold text-white/40">/ 10</span>
                            </div>
                            <span className="text-[10px] font-black text-white/40 uppercase tracking-[0.3em] mt-2">Avaliação IMDb</span>
                        </div>
                    </div>
                )}

                {/* Synopsis */}
                <p className="text-lg text-white/70 leading-relaxed">
                    {movie.synopsis}
                </p>

                {/* Availability */}
                <Section title="Onde Assistir">
                    <div className="flex flex-wrap gap-3">
