        className="w-full h-full md:max-w-2xl md:h-[95vh] md:rounded-[2.5rem] bg-[#030712] flex flex-col overflow-hidden relative shadow-2xl animate-slide-up"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header de Controle Superior */}
        <div className="absolute top-0 left-0 right-0 z-50 flex items-center justify-between p-6">
             <button onClick={onClose} className="p-2 text-brand-accent hover:opacity-80 transition-opacity">
                <Bars3Icon className="w-8 h-8" />
             </button>
        </div>

        <div className="flex-1 overflow-y-auto no-scrollbar scroll-smooth">
            {/* ÁREA DO POSTER - FIEL À REFERÊNCIA */}
            <div className="relative w-full aspect-[4/5] flex-shrink-0">
                <img
                    src={movie.posterUrl}
                    alt={movie.title}
                    className="w-full h-full object-cover object-top"
                    referrerPolicy="no-referrer"
                />

                {/* Overlay Gradiente Inferior para o Título */}
                <div className="absolute inset-0 bg-gradient-to-t from-[#030712] via-[#030712]/20 to-transparent"></div>

                {/* BOTÕES DE AÇÃO FLUTUANTES (STACK VERTICAL À DIREITA) */}
                <div className="absolute top-12 right-6 flex flex-col gap-4 items-center">
                    <button 
                        onClick={openTrailer} 
                        disabled={!movie.trailerUrl}
                        className="p-3.5 rounded-full bg-black/40 backdrop-blur-xl text-white border border-white/10 active:scale-90 transition-all disabled:opacity-20"
                    >
                        <PlayIcon className="w-6 h-6" />
                    </button>
                    <button 
                        onClick={onShareClick}
                        className="p-3.5 rounded-full bg-black/40 backdrop-blur-xl text-white border border-white/10 active:scale-90 transition-all"
                    >
                        <ShareIcon className="w-6 h-6" />
                    </button>
                    <button 
                        onClick={onToggleWatchlist}
                        className={`p-3.5 rounded-full backdrop-blur-xl border border-white/10 active:scale-90 transition-all ${isInWatchlist ? 'bg-white text-black' : 'bg-black/40 text-white'}`}
                    >
                        <BookmarkIcon className="w-6 h-6" />
                    </button>
                    <button 
                        onClick={onToggleWatched}
                        className={`p-3.5 rounded-full backdrop-blur-xl border border-white/10 active:scale-90 transition-all ${isInWatchedList ? 'bg-emerald-500 text-white' : 'bg-black/40 text-white'}`}
                    >
                        <ClockIcon className="w-6 h-6" />
                    </button>
                    <button 
                        className="p-3.5 rounded-full bg-black/40 backdrop-blur-xl text-white border border-white/10 active:scale-90 transition-all"
                    >
                        <NoSymbolIcon className="w-6 h-6" />
                    </button>
                </div>

                {/* TEXTO DO POSTER (TÍTULO E ANO) */}
                <div className="absolute bottom-6 left-8 right-8">
                    <p className="text-sm font-bold text-gray-400 mb-1 uppercase tracking-wide">
                        {movie.type === 'Movie' ? 'Filme' : 'Série'}
                    </p>
                    <h2 className="text-4xl font-black text-white tracking-tighter leading-none">
                        {movie.title} ({movie.year})
                    </h2>
                </div>
            </div>

            {/* ÁREA DE CONTEÚDO (SCROLL) */}
            <div className="px-8 pb-20 space-y-12 bg-[#030712]">

                {/* BLOCO DE NOTA IMDB - IGUAL À IMAGEM */}
                <div className="pt-10 flex flex-col items-center">
                    <div className="flex items-baseline justify-center gap-2">
                        <span className="text-7xl font-black text-white tracking-tighter">
                            {movie.ratings.imdb > 0 ? movie.ratings.imdb.toFixed(1) : 'N/A'}
                        </span>
                        <span className="text-3xl font-bold text-white/30">/ 10</span>
                    </div>
                    <p className="text-[11px] font-black text-white/40 uppercase tracking-[0.4em] mt-3">AVALIAÇÃO IMDB</p>

                    {/* Divisor Sutil */}
                    <div className="w-full max-w-[200px] h-[1px] bg-white/10 mt-12"></div>
                </div>

                {/* SINOPSE */}
                <div className="animate-fade-in-up">
                    <p className="text-xl text-white/80 leading-relaxed font-medium">
                        {movie.synopsis}
                    </p>
                </div>

                {/* ONDE ASSISTIR - ESTILIZADO */}
                <div className="space-y-6 pt-4 border-t border-white/5">
                    <h3 className="text-xs font-black text-white/40 uppercase tracking-[0.3em]">ONDE ASSISTIR</h3>
                    <div className="flex flex-wrap gap-4">
                        {movie.availability?.flatrate && movie.availability.flatrate.length > 0 ? (
                            movie.availability.flatrate.map(p => <ProviderIcon key={p.provider_id} provider={p} />)
                        ) : (
                            <p className="text-lg font-semibold text-white/40 italic">Em breve nos streamings.</p>
                        )}
                    </div>
                </div>

                {/* ELENCO */}
                <div className="space-y-6">
                    <h3 className="text-xs font-black text-white/40 uppercase tracking-[0.3em]">ELENCO PRINCIPAL</h3>
                    <div className="flex overflow-x-auto space-x-6 pb-2 no-scrollbar">
                        {movie.director && <CreditCard person={movie.director} />}
                        {movie.cast.slice(0, 10).map(person => <CreditCard key={person.id} person={person} />)}
                    </div>
                </div>

                {/* RECOMENDAÇÕES */}
                <div className="space-y-6">
                    <h3 className="text-xs font-black text-white/40 uppercase tracking-[0.3em]">VOCÊ TAMBÉM PODE GOSTAR</h3>
                    <div className="flex overflow-x-auto space-x-4 pb-4 no-scrollbar">
                        {movie.recommendations.map(rec => (
                            <div 
                                key={rec.id} 
                                onClick={() => onRecommendationClick(rec)} 
                                className="flex-shrink-0 w-32 group cursor-pointer"
                            >
                                <div className="relative aspect-[2/3] rounded-2xl overflow-hidden bg-white/5 border border-white/5 transition-transform group-hover:scale-105">
                                    {rec.posterUrl && <img src={rec.posterUrl} alt="" className="w-full h-full object-cover"/>}
                                </div>
                                <h4 className="text-[10px] font-black uppercase tracking-widest mt-3 text-white/20 truncate group-hover:text-white transition-colors">{rec.title}</h4>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Movie } from '../types';
import { BookmarkIcon, ImdbIcon, CheckCircleIcon, ClockIcon, PlayIcon, FilmIcon, NoSymbolIcon, ShareIcon } from './Icons';
import { StreamingPill } from './StreamingPill';

interface MovieCardProps {
  movie: Movie;
  onToggleWatchlist: () => void;
  isInWatchlist: boolean;
  onToggleWatched: () => void;
  isInWatchedList: boolean;
  onClick: () => void;
  onToggleNotInterested: () => void;
  isNotInterested: boolean;
  onShareClick: () => void;
}

export const MovieCard: React.FC<MovieCardProps> = ({ movie, onToggleWatchlist, isInWatchlist, onToggleWatched, isInWatchedList, onClick, onToggleNotInterested, isNotInterested, onShareClick }) => {
  const [isImgError, setIsImgError] = React.useState(false);

  const handleActionClick = (e: React.MouseEvent, action: () => void) => {
    e.stopPropagation();
    action();
  };

  const releaseDate = new Date(movie.releaseDate);
  const today = new Date();
  const isNewRelease = movie.type === 'Movie' && releaseDate.getFullYear() === today.getFullYear() && releaseDate.getMonth() >= today.getMonth() - 1;

  return (
    <div 
      onClick={onClick}
      className={`group relative bg-gray-900 rounded-2xl overflow-hidden transition-all duration-500 hover:shadow-2xl hover:shadow-brand-accent/10 cursor-pointer ${isInWatchedList ? 'opacity-40 grayscale hover:opacity-100 hover:grayscale-0' : ''}`}>

      {/* Poster Image - Rollover apenas aqui */}
      <div className="aspect-[2/3] overflow-hidden bg-gray-800">
        {isImgError || !movie.posterUrl ? (
           <div className="w-full h-full flex flex-col items-center justify-center text-center p-6">
                <FilmIcon className="w-12 h-12 text-gray-600 mb-3" />
                <span className="text-white font-bold text-lg leading-tight">{movie.title}</span>
            </div>
        ) : (
            <img 
                src={movie.posterUrl} 
                alt={movie.title} 
                className="w-full h-full object-cover transition-transform duration-700 ease-out group-hover:scale-110"
                referrerPolicy="no-referrer"
                onError={() => setIsImgError(true)}
                loading="lazy"
            />
        )}
      </div>

      {/* Overlay de Conteúdo Gradiente */}
      <div className="absolute inset-0 movie-card-gradient flex flex-col justify-end p-5 pointer-events-none">
        <div className="flex items-center justify-between mb-2">
           <div className="flex gap-1.5">
             {isNewRelease && (
                <span className="bg-amber-400 text-black text-[10px] font-black px-2 py-0.5 rounded uppercase tracking-tighter">Estreia</span>
             )}
             <span className="bg-white/10 backdrop-blur-md text-white text-[10px] font-bold px-2 py-0.5 rounded uppercase">{movie.type === 'Movie' ? 'Filme' : 'Série'}</span>
           </div>
           {movie.ratings.imdb > 0 && (
              <div className="flex items-center bg-black/60 backdrop-blur-md px-2 py-0.5 rounded border border-white/10">
                <span className="text-amber-400 font-black text-xs">{movie.ratings.imdb.toFixed(1)}</span>
                <span className="text-white/60 text-[9px] ml-0.5 font-black uppercase tracking-tighter">IMDb</span>
              </div>
           )}
        </div>

        <h2 className="text-xl font-extrabold text-white leading-tight mb-1 group-hover:text-brand-accent transition-colors">
          {movie.title}
        </h2>

        <div className="flex items-center text-gray-400 text-xs font-medium space-x-3">
           <span>{movie.year}</span>
           {movie.durationInMinutes > 0 && <span>• {movie.durationInMinutes}min</span>}
        </div>
      </div>

      {/* Ações Rápidas (Sempre Visíveis em Dispositivos Móveis ou em Hover no Desktop) */}
      <div className="absolute top-4 right-4 flex flex-col gap-2 transition-all duration-300">
          <button
            onClick={(e) => handleActionClick(e, onToggleWatchlist)}
            className={`p-2.5 rounded-xl backdrop-blur-xl border border-white/10 transition-all hover:scale-110 active:scale-95 ${
              isInWatchlist ? 'bg-white text-black' : 'bg-black/60 text-white hover:bg-white hover:text-black'
            }`}
          >
            <BookmarkIcon className="w-5 h-5" />
          </button>
          <button
            onClick={(e) => handleActionClick(e, onShareClick)}
            className="p-2.5 rounded-xl backdrop-blur-xl bg-black/60 border border-white/10 text-white hover:bg-white hover:text-black transition-all hover:scale-110 active:scale-95"
          >
            <ShareIcon className="w-5 h-5" />
          </button>
          <button
            onClick={(e) => handleActionClick(e, onToggleNotInterested)}
            className={`p-2.5 rounded-xl backdrop-blur-xl border border-white/10 transition-all hover:scale-110 active:scale-95 ${
              isNotInterested ? 'bg-red-500 text-white' : 'bg-black/60 text-white hover:bg-red-500'
            }`}
          >
            <NoSymbolIcon className="w-5 h-5" />
          </button>
      </div>
    </div>
  );
};
